using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Warehouses;

/// <summary>Provides workspace-scoped persistence operations for warehouses.</summary>
public interface IWarehouseCatalog
{
    /// <summary>Creates a warehouse.</summary>
    Task<Warehouse> CreateAsync(Warehouse warehouse, CancellationToken cancellationToken);
    /// <summary>Lists active warehouses.</summary>
    Task<IReadOnlyList<Warehouse>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken);
    /// <summary>Finds a warehouse only within its workspace.</summary>
    Task<Warehouse?> FindAsync(Guid workspaceId, Guid warehouseId, CancellationToken cancellationToken);
    /// <summary>Archives a warehouse only when no nonzero workspace balance references it.</summary>
    Task<bool> ArchiveAsync(Guid workspaceId, Guid warehouseId, DateTimeOffset archivedAtUtc, CancellationToken cancellationToken);
    /// <summary>Persists pending changes.</summary>
    Task SaveChangesAsync(CancellationToken cancellationToken);
}

/// <summary>Represents a duplicate canonical warehouse name within a workspace.</summary>
public sealed class WarehouseNameConflictException : Exception
{
    /// <summary>Initializes the exception.</summary>
    public WarehouseNameConflictException() : base("A warehouse with this name already exists in the workspace.") { }
}

using InventoryFlow.Domain.Entities;
using MediatR;

namespace InventoryFlow.Application.Features.Warehouses;

/// <summary>Handles warehouse creation.</summary>
public sealed class CreateWarehouseHandler(IWarehouseCatalog catalog, TimeProvider timeProvider)
    : IRequestHandler<CreateWarehouseCommand, WarehouseResponse>
{
    /// <inheritdoc />
    public async Task<WarehouseResponse> Handle(CreateWarehouseCommand request, CancellationToken cancellationToken) =>
        WarehouseResponse.From(await catalog.CreateAsync(new Warehouse(Guid.NewGuid(), request.WorkspaceId, request.Name,
            timeProvider.GetUtcNow()), cancellationToken));
}

/// <summary>Handles active warehouse listing.</summary>
public sealed class ListWarehousesHandler(IWarehouseCatalog catalog)
    : IRequestHandler<ListWarehousesQuery, IReadOnlyList<WarehouseResponse>>
{
    /// <inheritdoc />
    public async Task<IReadOnlyList<WarehouseResponse>> Handle(ListWarehousesQuery request, CancellationToken cancellationToken) =>
        (await catalog.ListActiveAsync(request.WorkspaceId, cancellationToken)).Select(WarehouseResponse.From).ToArray();
}

/// <summary>Handles warehouse archival.</summary>
public sealed class ArchiveWarehouseHandler(IWarehouseCatalog catalog, TimeProvider timeProvider)
    : IRequestHandler<ArchiveWarehouseCommand, bool>
{
    /// <inheritdoc />
    public Task<bool> Handle(ArchiveWarehouseCommand request, CancellationToken cancellationToken) =>
        catalog.ArchiveAsync(request.WorkspaceId, request.WarehouseId, timeProvider.GetUtcNow(), cancellationToken);
}

using System.Data;
using InventoryFlow.Application.Features.Inventory;
using InventoryFlow.Application.Features.Products;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.Data.SqlClient;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Products;

/// <summary>Persists workspace-scoped products with SQL Server uniqueness and lifecycle handling.</summary>
public sealed class EfProductCatalog(ApplicationDbContext dbContext) : IProductCatalog
{
    /// <inheritdoc />
    public async Task<Product> CreateAsync(Product product, CancellationToken cancellationToken)
    {
        dbContext.Products.Add(product);
        try
        {
            await dbContext.SaveChangesAsync(cancellationToken);
            return product;
        }
        catch (DbUpdateException exception) when (exception.InnerException is SqlException { Number: 2601 or 2627 })
        {
            throw new ProductSkuConflictException();
        }
    }

    /// <inheritdoc />
    public async Task<IReadOnlyList<Product>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.Products.AsNoTracking().Where(item => item.WorkspaceId == workspaceId && item.ArchivedAtUtc == null)
            .OrderBy(item => item.Name).ThenBy(item => item.Id).ToListAsync(cancellationToken);

    /// <inheritdoc />
    public Task<Product?> FindAsync(Guid workspaceId, Guid productId, CancellationToken cancellationToken) =>
        dbContext.Products.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId && item.Id == productId, cancellationToken);

    /// <inheritdoc />
    public async Task<bool> ArchiveAsync(Guid workspaceId, Guid productId, DateTimeOffset archivedAtUtc,
        CancellationToken cancellationToken)
    {
        var strategy = dbContext.Database.CreateExecutionStrategy();
        return await strategy.ExecuteAsync(async () =>
        {
            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
            var product = await dbContext.Products.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
                item.Id == productId, cancellationToken);
            if (product is null)
            {
                await transaction.RollbackAsync(cancellationToken);
                return false;
            }

            var hasOnHandBalance = await dbContext.InventoryBalances.AnyAsync(balance => balance.WorkspaceId == workspaceId &&
                balance.ProductId == productId && balance.Quantity != 0m, cancellationToken);
            if (hasOnHandBalance)
            {
                await transaction.RollbackAsync(cancellationToken);
                throw new InventoryArchiveConflictException();
            }

            product.Archive(archivedAtUtc);
            await dbContext.SaveChangesAsync(cancellationToken);
            await transaction.CommitAsync(cancellationToken);
            return true;
        });
    }

    /// <inheritdoc />
    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
}

using System.Data;
using InventoryFlow.Application.Features.Inventory;
using InventoryFlow.Application.Features.Warehouses;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.Data.SqlClient;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Warehouses;

/// <summary>Persists workspace-scoped warehouses with SQL Server lifecycle handling.</summary>
public sealed class EfWarehouseCatalog(ApplicationDbContext dbContext) : IWarehouseCatalog
{
    /// <inheritdoc />
    public async Task<Warehouse> CreateAsync(Warehouse warehouse, CancellationToken cancellationToken)
    {
        dbContext.Warehouses.Add(warehouse);
        try
        {
            await dbContext.SaveChangesAsync(cancellationToken);
            return warehouse;
        }
        catch (DbUpdateException exception) when (exception.InnerException is SqlException { Number: 2601 or 2627 })
        {
            throw new WarehouseNameConflictException();
        }
    }

    /// <inheritdoc />
    public async Task<IReadOnlyList<Warehouse>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.Warehouses.AsNoTracking().Where(warehouse => warehouse.WorkspaceId == workspaceId &&
            warehouse.ArchivedAtUtc == null).OrderBy(warehouse => warehouse.Name).ThenBy(warehouse => warehouse.Id)
            .ToListAsync(cancellationToken);

    /// <inheritdoc />
    public Task<Warehouse?> FindAsync(Guid workspaceId, Guid warehouseId, CancellationToken cancellationToken) =>
        dbContext.Warehouses.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId && item.Id == warehouseId,
            cancellationToken);

    /// <inheritdoc />
    public async Task<bool> ArchiveAsync(Guid workspaceId, Guid warehouseId, DateTimeOffset archivedAtUtc,
        CancellationToken cancellationToken)
    {
        var strategy = dbContext.Database.CreateExecutionStrategy();
        return await strategy.ExecuteAsync(async () =>
        {
            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
            var warehouse = await dbContext.Warehouses.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
                item.Id == warehouseId, cancellationToken);
            if (warehouse is null)
            {
                await transaction.RollbackAsync(cancellationToken);
                return false;
            }

            var hasOnHandBalance = await dbContext.InventoryBalances.AnyAsync(balance => balance.WorkspaceId == workspaceId &&
                balance.WarehouseId == warehouseId && balance.Quantity != 0m, cancellationToken);
            if (hasOnHandBalance)
            {
                await transaction.RollbackAsync(cancellationToken);
                throw new InventoryArchiveConflictException();
            }

            warehouse.Archive(archivedAtUtc);
            await dbContext.SaveChangesAsync(cancellationToken);
            await transaction.CommitAsync(cancellationToken);
            return true;
        });
    }

    /// <inheritdoc />
    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
}

